(function(){function ready(fn){if(document.readyState!=="loading"){fn()}else{document.addEventListener("DOMContentLoaded",fn)}}ready(function(){document.querySelectorAll('.wz-opt input[type="checkbox"]').forEach(function(cb){cb.addEventListener("change",function(){var row=cb.closest(".wz-opt");if(row){row.classList.toggle("is-on",cb.checked)}})});document.querySelectorAll("[data-gw-toggle]").forEach(function(cb){cb.addEventListener("change",function(){var card=cb.closest("[data-gw]");if(card){card.classList.toggle("is-on",cb.checked)}})})})})();